oxy_webhelp_navlinks = {"cli_administrator_role-d27243e2956":{"topics":[{"title":"CLI access through SSH","shortdesc":"<p class=\"shortdesc\">SSH protocol is the standard way for Rubrik CDM users to access the Rubrik CLI. To         use the SSH protocol, users require both administrator and CLI administrator         roles.<\/p>","href":"cdm_old\/cli_access_through_ssh.html","attributes":{"data-id":"cli_access_through_ssh"},"menu":{"hasChildren":false},"tocID":"cli_access_through_ssh-d27243e2967","topics":[]},{"title":"Disabling SSH password authentication","shortdesc":"<p class=\"shortdesc\">Disable password authentication for Secure Shell sessions to authenticate using SSH         key pairs.<\/p>","href":"cdm_old\/disabling_ssh_passwords.html","attributes":{"data-id":"disabling_ssh_passwords"},"menu":{"hasChildren":false},"tocID":"disabling_ssh_passwords-d27243e2978","topics":[]},{"title":"Configuring Rubrik CLI SSH Key authentication","shortdesc":"<p class=\"shortdesc\">You can assign an SSH key to a user account. With this key, users can authenticate as         a Rubrik cluster administrator without needing to transmit an account password.<\/p>","href":"cdm_old\/config_auth_rubrik_cli_ssh.html","attributes":{"data-id":"config_ssh_key_auth_for_cli"},"menu":{"hasChildren":false},"tocID":"config_ssh_key_auth_for_cli-d27243e2989","topics":[]}]}};